class Solution:
    def maxPathSum(self, root):
        # Brute force: enumerate every node as the bend point and, for each,
        # find the best downward path on each side by full subtree search.
        nodes = []
        def collect(node):
            if node is None:
                return
            nodes.append(node)
            collect(node.left)
            collect(node.right)
        collect(root)
        def best_down(node):
            if node is None:
                return 0
            return node.val + max(0, best_down(node.left), best_down(node.right))
        best = None
        for node in nodes:
            l = max(0, best_down(node.left))
            r = max(0, best_down(node.right))
            cand = node.val + l + r
            best = cand if best is None else max(best, cand)
        return best

