class Solution:
    def maxPathSum(self, root):
        self.best = float('-inf')
        def gain(node):
            if node is None:
                return 0
            left = max(0, gain(node.left))
            right = max(0, gain(node.right))
            self.best = max(self.best, node.val + left + right)
            return node.val + max(left, right)
        gain(root)
        return self.best

